sql:
SELECT typology, num_sites, land_area, percent_total_area, ha_per_1000_population, average_quality_score
FROM green_spaces
WHERE typology = 'Natural/Semi';

external_knowledge:
- 'Singing the melody of tranquility' refers to sites that comply with the 'Noise Ordinance';
- 'Elevate themselves above the humdrum' signifies sites that have a quality score higher than the average quality score of all sites;
- 'Towering peaks' metaphorically represents sites with scores above the average;
- 'Quality score' is measured on a scale of 0-100, indicating the quality of the site.

sql:
SELECT DISTINCT u.user_name
FROM users u
JOIN user_feedback uf ON u.user_id = uf.user_id;

external_knowledge:
- 'voyagers' refers to the distinct users who accessed the site;
- 'digital gates' metaphorically represents the access points to the site;
- 'castle' is a metaphor for the site itself;
- 'dawn and dusk of our chosen period' refers to the 'start_date' and 'end_date' in the SQL query.

sql:
SELECT sf.feature_type, sf.description, s.site_name, s.location
FROM site_features sf 
INNER JOIN sites s ON sf.site_id = s.site_id;

SELECT space_id, typology, average_quality_score
FROM green_spaces
ORDER BY average_quality_score DESC;

SELECT sp.*, s.*
FROM site_policies sp
JOIN sites s ON sp.site_id = s.site_id;

SELECT typology, MAX(last_updated) as most_recent_last_updated
FROM green_spaces
GROUP BY typology;

SELECT site_name 
FROM sites 
WHERE quality_score < (SELECT AVG(quality_score) FROM sites);

SELECT 
    (SELECT AVG(average_quality_score) FROM green_spaces) AS green_space_avg_quality,
    (SELECT AVG(quality_score) FROM sites) AS site_avg_quality;

external_knowledge:
- "Gardeners" refers to the users providing feedback;
- "Tending the garden" alludes to the user's role within the system;
- "Flowers they have planted" metaphorically represents the feedback entries given by users;
- "Different plots" symbolize the various sites where feedback was provided.

sql:
SELECT typology
FROM green_spaces
WHERE average_quality_score = (SELECT MAX(average_quality_score) FROM green_spaces);

SELECT feedback_text, rating, response
FROM user_feedback
WHERE user_id = 0 AND site_id = 0;

SELECT e.event_name
FROM site_events e
WHERE e.site_id = 0;

SELECT g.space_id, g.typology, g.land_area, g.average_quality_score
FROM green_spaces g
WHERE g.land_area > (
    SELECT AVG(land_area)
    FROM green_spaces
)
AND g.average_quality_score < (
    SELECT AVG(quality_score)
    FROM sites
);

SELECT typology, average_quality_score
FROM green_spaces
ORDER BY typology;
